// Re-assert the first ensures conjunct for r1 and r2 with identical
// forall bodies so the disjoint quantifier triggers line up and z3
// can see r1.0 and r2.0 are both equated to the same spec value.
assert(r1.0 == forall|i: int| #![auto] lo <= i <= hi ==> self_@[self_.keys@[i]]@ == v@);
assert(r2.0 == forall|i: int| #![auto] lo <= i <= hi ==> self_@[self_.keys@[i]]@ == v@);
assert(r1.0 == r2.0);

if !r1.0 {
    assert(!r2.0);
    // Re-assert the second ensures conjunct so the .1 components also align.
    assert(r1.1 == (self_@[self_.keys@[hi as int]]@ != v@
        && (forall|i: int| #![auto] lo <= i < hi ==> self_@[self_.keys@[i]]@ == v@)));
    assert(r2.1 == (self_@[self_.keys@[hi as int]]@ != v@
        && (forall|i: int| #![auto] lo <= i < hi ==> self_@[self_.keys@[i]]@ == v@)));
    assert(r1.1 == r2.1);
}
